Good idea! Use custom error types that implement `IntoResponse` or define errors with status codes:

```rust
#[derive(Debug, thiserror::Error)]
pub enum MyErrors {
    #[error("Invalid param: {0}")]
    InvalidParam(String),
}

impl axum::response::IntoResponse for MyErrors {
    fn into_response(self) -> axum::http::Response<axum::body::Body> {
        let (status, body) = match self {
            MyErrors::InvalidParam(_) => (
                http::StatusCode::BAD_REQUEST,
                serde_json::json!({"error": "Invalid param"}).to_string(),
            ),
        };

        (status, axum::body::Body::from(body)).into_response()
    }
}
```
